For Each Order EmpCod, PesCod
	Where EmpCod = &EmpCod
	Where PesCod = &FunPesCod
	&FunPesRaz = PesRaz
	exit
EndFor

For Each Order EmpCod, FilCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCod
	&FilBasImp = FilBasImp
	&FilFan = FilFan
	if not FilFonNum.IsEmpty()
		&FoneVarchar = 'FONE: ' + trim(FilFonNum)
	EndIF
	Exit
EndFor

	MB 4
	MT 2

	Header
		print Cabecalho
	End

