sub 'GetLocalCobranca'
	&CbrCodNom = ''
	For Each Order EmpCod, CbrCod
		Where EmpCod = &EmpCod
		Where CbrCod = &NfeCbrCod

		&CbrCodNom = CbrCodNom.Trim()
		Exit
	EndFor
EndSub
